export const getCompanyById = (id: string): Company | undefined => {
  return companies.find(c => c.id === id);
};

export const getCompanyProblemById = (companyId: string, problemId: number): CompanyProblem | undefined => {
  const company = getCompanyById(companyId);
  return company?.problems.find(p => p.id === problemId);
};
